sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onLoad() {
    var taskPermissions = JSON.parse(g_scratchpad.taskPermissions);

    // NOTE: saving the base form before opening modal, but modal opens asynchronously
    //       so, it is possible the data in here needs to be refreshed.  There is an idea taking the form feilds and passing 
    //       to the taskPermissions to update that could be used to ensure fresh
	var isTaskManagerOUTA = taskPermissions.isTaskManagerOUTA;
    var isTAExternal = taskPermissions.isTAExternal == true;
    var reviewerInOUTA_OU = taskPermissions.reviewerInOUTA_OU;
    var isSubTask = taskPermissions.isSubTask;
    var currentUser = g_user.userID;
    var isTaskerApplicationAdmin = g_user.hasRoleExactly("x_153465_discovert.tasker_application_admin");
    var isTaskAdministratorGTA = g_user.hasRoleExactly("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
    var isTaskerUser = g_user.hasRoleExactly("x_153465_discovert.tasker_user");
    var isParentTaskOwner = taskPermissions.parentTaskOwner == currentUser;
    var isParentTaskAssignedMember = taskPermissions.parentTaskAssignedMember == currentUser;
    var isOnBehalfOf = taskPermissions.on_behalf_of == currentUser;
    var isReviewer = taskPermissions.reviewer == currentUser;
    var isReviewRequired = taskPermissions.isReviewRequired;
    var isTaskOwner = taskPermissions.taskOwner == currentUser;
    var isAssignedMember = taskPermissions.assignedMember == currentUser;
    var state = (g_form.isNewRecord()) ? "New" : taskPermissions.state;
    //  2.5.316 - RJ - Adjust Read Only settings into Permissions
    var primaryOUMustMatchInternalTAOU = (g_scratchpad.primary_office_must_match_Internal_tasking_authority == 'true');

    var isReviewType = (g_scratchpad.taskType == 'Concur with signature' 
						|| g_scratchpad.taskType == 'Approval without signature' 
						|| g_scratchpad.taskType == 'Approval with signature' 
						|| g_scratchpad.taskType == 'Concur without signature');
    var isStandardType = (g_scratchpad.taskType == 'Standard');
    /*
	//var newLine = "\r\n";
	var msg = "KT isSubTask: " + isSubTask + newLine;
	msg += "state: " + state + newLine;
	msg += "isTaskerApplicationAdmin: " + isTaskerApplicationAdmin + newLine;
	msg += "isTaskAdministratorGTA: " + isTaskAdministratorGTA + newLine;
	msg += "isTaskManagerOUTA: " + isTaskManagerOUTA + newLine;
	msg += "isOnBehalfOf: " + isOnBehalfOf + newLine;
	msg += "isReviewer: " + isReviewer + newLine;
	msg += "isTaskOwner: " + isTaskOwner + newLine;
	msg += "isAssignedMember: " + isAssignedMember + newLine;
	msg += "isParentTaskOwner: " + isParentTaskOwner + newLine;
	msg += "isParentTaskAssignedMember: " + isParentTaskAssignedMember + newLine;
 	*/

    function makeReadOnly(fields, value) {
        if (Array.isArray(fields)) {
            for (var i = 0; i < fields.length; ++i) {
                g_form.setDisabled(fields[i], value);
            }
        } else {
            g_form.setDisabled(fields, value);
        }
    }

    makeReadOnly(["assigned_to", "primary_assignee"], true);
    makeReadOnly("tasking_authority", false);

    var permissionsCalc = {};

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: NEW
    //------------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc.setPermissionsNew = function() {
        //2.5.13 |  KT | STRY0063495
        switch (isSubTask) {
            //--------- TOP TASK
            case false:
                // STRY0085187
                if (isTaskerUser) {
                    //STRY0074111 STRY0085538
                    makeReadOnly(["tasking_authority", "primary_assignee", "assigned_to", "u_reviewer", 
								"provide_response"], false);
                    makeReadOnly(["response", "rework_comments"], true);
                    //  2.5.316 - RJ - Adjust Read Only settings into Permissions
                    makeReadOnly("primary_office", primaryOUMustMatchInternalTAOU);
                }
                if (isTaskManagerOUTA) makeReadOnly(["tasking_authority", "u_reviewer"], false);
                if (isTaskAdministratorGTA) makeReadOnly(["tasking_authority", "u_reviewer"], false);
                if (isTaskerApplicationAdmin) makeReadOnly(["primary_assignee"], false); //2.5.13 |  KT | STRY0063495: Updated Reqs. Since 2.5 ALL offices are Tasking Authorities.
                break;
                //--------- SUB TASK
            case true:
                // STRY0085187
                if (isTaskerUser) {
                    //STRY0074111 STRY0085538
                    makeReadOnly(["tasking_authority", "primary_assignee", 
								"provide_response", "response", "rework_comments"], true);
                }
                if (isTaskManagerOUTA) makeReadOnly(["tasking_authority", "primary_assignee"], true);
                if (isTaskAdministratorGTA) makeReadOnly("tasking_authority", true);
                if (isParentTaskAssignedMember) makeReadOnly(["primary_assignee", "provide_response"], false);
                // STRY0083372 "Assigned Member" field must be editable on "New" sub task form.
                // "Primary Assignee" field needs to be editable by the Parent Task Owner
                if (isParentTaskOwner) makeReadOnly(["primary_assignee"], false);

                // STRY0083372 "Assigned Member" field must be editable on "New" sub task form.
                if (isTaskerUser) makeReadOnly(["primary_assignee", "assigned_to"], false);
                //  2.5.316 - RJ - Adjust Read Only settings into Permissions
                makeReadOnly("primary_office", false); // on subtask can't change primary office

                break;
        }
    };

    //2.5.14: 08.21.20 |  KT | STRY0078381: 2.5 Patch 2 Smoke Test - Navigating to any task in "Wait" state displays a JavaScript Error
    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: WAITING
    //------------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc["setPermissions-3"] = function() {

    };

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: UNASSIGNED
    //------------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc["setPermissions-5"] = function() {

        if (isTaskerUser) {
            //STRY0074111 STRY0085187 //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly(["tasking_authority", "primary_office", "primary_assignee", "u_reviewer", "response", 
						"provide_response", "comments_dt", "rework_comments"], true);

            makeReadOnly("assigned_to", false);
            if (isSubTask) {
                makeReadOnly("assigned_to", false);
                if (true) {
                    // if isTaskerUser is in OU, do this later
                }
            }

        }

        // Tasker Application Admin
        if (isTaskerApplicationAdmin) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly(["tasking_authority", "primary_office", "primary_asssignee",
                "assigned_to", "u_reviewer"
            ], true);
            if (isSubTask) {
                makeReadOnly("assigned_to", true);
            }
        }
        if (isReviewer) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly(["tasking_authority", "primary_office", "primary_assignee",
                "assigned_to", "u_reviewer"], true);
			if(isReviewType || isStandardType){
				makeReadOnly(["comments_dt"], false);
			}
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}

        }

        if (isOnBehalfOf) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["assigned_to", "u_reviewer"], true);
            makeReadOnly(["tasking_authority", "primary_assignee", "provide_response"], false);
			if(isReviewType || isStandardType){
				makeReadOnly(["comments_dt"], false);
			}
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }
        if (isTaskOwner) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly("u_reviewer", false);
            // STRY0085187
            makeReadOnly("provide_response", false);
            makeReadOnly("assigned_to", true);
            makeReadOnly(["tasking_authority", "primary_assignee"], false);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
			if(isReviewType || isStandardType){
				makeReadOnly(["comments_dt"], false);
			}
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
        }

        if (isTaskManagerOUTA) {
            makeReadOnly("u_reviewer", true);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["tasking_authority", "primary_assignee", "assigned_to"], false);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
            if (reviewerInOUTA_OU) {
                makeReadOnly("u_reviewer", isReviewRequired);
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isTaskAdministratorGTA) {
            makeReadOnly("u_reviewer", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["tasking_authority", "primary_assignee", "assigned_to"], false);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }
        //KB - STRY0032629 10/16/2019
        GtaOutaOfTaskOwnerMayEdit();
    };

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: ASSIGNED
    //----------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc.setPermissions1 = function() {

        // normal tasker user
        if (isTaskerUser) {
            // STRY0085187 STRY0074111 STRY0085538
            makeReadOnly(["tasking_authority", "assigned_to", "provide_response", "u_reviewer", 
						"response", "rework_comments", "comments_dt"], true);
            if (true) {
                // if isTaskerUser is in OU, do this later
            }
            if (isSubTask) {}
        }

        // Tasker Application Admin
        if (isTaskerApplicationAdmin) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly(["tasking_authority", "primary_office", "assigned_to", "u_reviewer"], true);
        }

        if (isAssignedMember) {
            makeReadOnly("u_reviewer", isReviewRequired);
            //STRY0074111
			if(isStandardType){
				makeReadOnly(["response"], false);
			}

            makeReadOnly(["tasking_authority", "primary_office", "assigned_to"], true);
            if (isSubTask) {
                makeReadOnly("u_reviewer", isReviewRequired);
            }
        }

        if (isReviewer) {
            makeReadOnly(["tasking_authority", "primary_office", "assigned_to", "u_reviewer"], true);
            if (isSubTask) {
                makeReadOnly(["u_reviewer"], true);
            }
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
        }

        if (isOnBehalfOf) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["tasking_authority, u_reviewer", "primary_assignee"], false); //2.5.13 |  KT | STRY0063495
            makeReadOnly(["assigned_to"], true);
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
            makeReadOnly("provide_response", false);
            if (isSubTask) makeReadOnly(["tasking_authority", "primary_office"], true);
        }

        if (isTaskOwner) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["tasking_authority", "primary_assignee"], false);
            makeReadOnly("assigned_to", true);
            makeReadOnly('u_reviewer', false);
            // STRY0085187
            makeReadOnly("provide_response", false);

            if (isSubTask) {
                makeReadOnly(["primary_office", "tasking_authority"], true);
            }
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
        }

        if (isTaskManagerOUTA) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["primary_assignee", "tasking_authority"], false);
            makeReadOnly(["u_reviewer", "assigned_to"], false);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
                makeReadOnly(["primary_assignee", "assigned_to"], false);
            }

            if (reviewerInOUTA_OU) {

                makeReadOnly("u_reviewer", isReviewRequired);
            } else {
                makeReadOnly("u_reviewer", true);
            }
        }

        if (isTaskAdministratorGTA) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly(["u_reviewer", "primary_assignee", "tasking_authority", "assigned_to"], false);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        //KB - STRY0032629 10/16/2019
        GtaOutaOfTaskOwnerMayEdit();
    };

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: ACCEPTED
    //------------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc.setPermissions10 = function() {

        if (isTaskerUser) {
            // STRY0085187 STRY0074111 STRY0085538
            makeReadOnly(["tasking_authority", "primary_office", "primary_assignee", "assigned_to",
                "provide_response", "response", "u_reviewer", "comments_dt", "rework_comments"], true);
        }

        if (isAssignedMember) {
            makeReadOnly("assigned_to", true);
            makeReadOnly("u_reviewer", isReviewRequired);

            //STRY0074111
			if(isStandardType){
				makeReadOnly(["response"], false);
			}

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        // Tasker Application Admin
        if (isTaskerApplicationAdmin) {
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly("tasking_authority", false);
            makeReadOnly(["assigned_to", "u_reviewer"], true);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }
        if (isReviewer) {
            makeReadOnly(["tasking_authority", "primary_office", "u_reviewer"], true);
            if (isSubTask) {
                makeReadOnly("assigned_to", true);
            }
        }

        if (isOnBehalfOf) {
            makeReadOnly("tasking_authority", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly(["u_reviewer", "provide_response"], false);
            makeReadOnly(["primary_assignee"], false); //2.5.13 |  KT | STRY0063495: Added. Primary Assigned is NOW editable.
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
                makeReadOnly("u_reviewer", false);
            }
        }

        if (isTaskOwner) {
            makeReadOnly("u_reviewer", false);
            makeReadOnly("tasking_authority", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly(["primary_assignee", "provide_response"], false); //2.5.13 |  KT | STRY0063495
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true); //2.5.13 |  KT | STRY0063495: Primary Assigned was removed. Now it is editable.
            }
        }

        if (isTaskManagerOUTA) {
            makeReadOnly(["assigned_to", "tasking_authority"], false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly("u_reviewer", true);

            if (!isSubTask) makeReadOnly(["primary_assignee"], false); //2.5.13 |  KT | STRY0063495

            if (isSubTask) {
                makeReadOnly(["primary_assignee"], false); //2.5.13 |  KT | STRY0063495
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isTaskAdministratorGTA) {
            makeReadOnly(["assigned_to", "tasking_authority", "u_reviewer", "primary_assignee"], false); //2.5.13 |  KT | STRY0063495
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            if (isSubTask) makeReadOnly(["tasking_authority", "primary_office"], true);
        }

        //KB - STRY0032629 10/16/2019
        GtaOutaOfTaskOwnerMayEdit();
    };

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: REJECTED
    //------------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc.setPermissionsRejectedAssignment = function() {
        if (isTaskerUser) {
            // STRY0085187 STRY0074111
            makeReadOnly(["tasking_authority", "primary_office", "primary_assignee",
                "u_reviewer", "provide_response", "response", "comments_dt"], true);
            makeReadOnly("assigned_to", false);

            // somehow make this isTaskerUser the assigned member option
        }

        // Tasker Application Admin
        if (isTaskerApplicationAdmin) {
            makeReadOnly(["tasking_authority", "u_reviewer"], false); //2.5.13 |  KT | STRY0063495: Removed. Primary Assigned is NOW read-only.
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly(["assigned_to", "primary_assignee"], true); //2.5.13 |  KT | STRY0063495: Added. Primary Assigned is NOW read-only.
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isReviewer) {
            makeReadOnly("tasking_authority", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
            makeReadOnly(["assigned_to", "u_reviewer"], true);
            if (isSubTask) {
                //KT - STRY0055354: added "assigned_to" to the array
                makeReadOnly(["tasking_authority", "primary_office", "primary_assignee",
                    "u_reviewer", "assigned_to"
                ], true);
            }
        }

        if (isOnBehalfOf) {
            makeReadOnly(["assigned_to"], true); //2.5.13 |  KT | STRY0063495: Removed. Primary Assigned is NOW editable.
            makeReadOnly(["tasking_authority", "u_reviewer", "primary_assignee"], false); //2.5.13 |  KT | STRY0063495: Added. Primary Assigned is NOW editable.
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
            makeReadOnly("provide_response", false);
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isTaskOwner) {
            makeReadOnly(["assigned_to"], true); //2.5.13 |  KT | STRY0063495: Removed. Primary Assigned is NOW editable.
            // STRY0085187
            makeReadOnly("provide_response", false);

            makeReadOnly(["tasking_authority", "u_reviewer", "primary_assignee"], false); //2.5.13 |  KT | STRY0063495: Added. Primary Assigned is NOW editable.
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isTaskManagerOUTA) {
            makeReadOnly("u_reviewer", true); //2.5.13 |  KT | STRY0063495: Changed. Primary Assigned is NOW editable.
            makeReadOnly("primary_assignee", false); //2.5.13 |  KT | STRY0063495: Added. Primary Assigned is NOW editable.
            makeReadOnly(["assigned_to", "tasking_authority"], false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office", "u_reviewer"], true);
            }
        }

        if (isTaskAdministratorGTA) {
            makeReadOnly("primary_assignee", false); //2.5.13 |  KT | STRY0063495: Changed. Primary Assigned is NOW editable.
            makeReadOnly(["assigned_to", "u_reviewer", "tasking_authority"], false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }
        //KB - STRY0032629 10/16/2019
        GtaOutaOfTaskOwnerMayEdit();
    };

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: REJECTED AT THE OU LEVEL
    //------------------------------------------------------------------------------------------------------------------------------------
    permissionsCalc.setPermissionsRejectedPrimaryAssignee = function() {

        if (isTaskerUser) {
            // STRY0085187 STRY0074111
            makeReadOnly(["tasking_authority", "primary_office", "assigned_to",
                "u_reviewer", "provide_response", "response", "comments_dt"], true);
        }

        // Tasker Application Admin
        if (isTaskerApplicationAdmin) {
            makeReadOnly("tasking_authority", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly("assigned_to", true);
            makeReadOnly("u_reviewer", true);
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isReviewer) {
            makeReadOnly("tasking_authority", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly("assigned_to", true);
            makeReadOnly("u_reviewer", true);
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}
            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isOnBehalfOf) {
            makeReadOnly("tasking_authority", false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly("assigned_to", true);
            makeReadOnly("provide_response", false);
            makeReadOnly("u_reviewer", false);
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
                makeReadOnly("u_reviewer", false);
            }
        }

        if (isTaskOwner) {
            makeReadOnly(["primary_assignee", "tasking_authority"], false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly("assigned_to", true);
            makeReadOnly("u_reviewer", false);
			if(isStandardType){
				makeReadOnly(["rework_comments"], false);
			}

            // STRY0085187
            makeReadOnly("provide_response", false);

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
                makeReadOnly("u_reviewer", false);
            }
        }

        if (isTaskManagerOUTA) {
            makeReadOnly(["primary_assignee", "tasking_authority"], false); //2.5.13 |  KT | STRY0063495: Added. Primary Assigned is NOW editable.
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            makeReadOnly("u_reviewer", true);

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }

        if (isTaskAdministratorGTA) {
            makeReadOnly(["assigned_to", "tasking_authority", "primary_assignee", "u_reviewer"], false);
            //  2.5.316 - RJ - Adjust Read Only settings into Permissions
            makeReadOnly("primary_office", (!isTAExternal && primaryOUMustMatchInternalTAOU));

            if (isSubTask) {
                makeReadOnly(["tasking_authority", "primary_office"], true);
            }
        }
        //KB - STRY0032629 10/16/2019
        GtaOutaOfTaskOwnerMayEdit();
    };

    //------------------------------------------------------------------------------------------------------------------------------------
    // STATE: WORK IN PROGRESS
