    //KB - STRY0035824 - 10/10/2019 - modify patch permissions to make tasking authority read-only if tasker user default ou is not ta
    // call this when tasking authority should be read only due to default ou not a Tasking Authority

    //KB - STRY0032629 - 10/15/2019 - modify patch permissions to make Task Owner field editable if current user is GTA or OUTA of task owner ou.
    function GtaOutaOfTaskOwnerMayEdit() {
        // skip logic if not top task
        if (g_form.getDisplayValue('parent') != '') {
            return;
        }
        try {
            var isTaskAdministratorGTA = g_user.hasRoleExactly("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
            // check isTaskAdministratorGTA
            if (isTaskAdministratorGTA) {
                g_form.setDisabled('u_task_requester', false);
                g_form.setReadOnly('u_task_requester', false);
            } else {
                // check isTaskManagerOUTA of task owner's default ou
                // STRY0085438 - remove ajax calls in onload
                if (g_scratchpad.isUserOUTAOfAnotherUserBasedOnDefaultOu == true) {
                    g_form.setDisabled('u_task_requester', false);
                    g_form.setReadOnly('u_task_requester', false);
                }

                // STRY0085438 - remove ajax calls in onload
                /*
                var taskOwnerId = g_form.getValue('u_task_requester');
                var OrgScripts = new GlideAjax("ClientOrganizationalScripts");
                OrgScripts.addParam('sysparm_name', 'isUserOUTAOfAnotherUserBasedOnDefaultOu');
                OrgScripts.addParam('OUTAUser', g_user.userID);
                OrgScripts.addParam('Subject', taskOwnerId);
                OrgScripts.getXML(function(response) {
                	var isTaskManagerOUTA = response.responseXML.documentElement.getAttribute("answer");
                	if (g_scratchpad.isUserOUTAOfAnotherUserBasedOnDefaultOu == "true") {
                		g_form.setDisabled('u_task_requester', false);
                		g_form.setReadOnly('u_task_requester', false);
                	}
                });
                */
            }
        } catch (e) {
            jslog("Task - Permissions: " + e);
        }
    }
